#include <cstdio>
#include <llvm/Support/raw_ostream.h>
#include <llvm/IR/ConstantRange.h>

int main() {
    using namespace llvm;

    // For ult i8 %a, 5 -> range is [0, 5)
    ConstantRange Range1(APInt(8, 0), APInt(8, 5));

    // For (a & -2) == 2:
    // -2 = 254 = 11111110 in i8
    // a & 11111110 == 00000010
    // This means a must have bit 1 set and bit 0 cleared
    // So a must be 2 or 3 -> but the ConstantRange approach would need
    // to handle this differently

    llvm::errs() << "Range for ult 5: [" << Range1.getLower() << ", " << Range1.getUpper() << ")\n";

    return 0;
}
EOF
"}

