/// Try to match patterns where (and (icmp ult/ule x, C1) (icmp eq (and x, Mask), C2))
/// can be simplified to just (icmp eq (and x, Mask), C2) when the values that
/// satisfy the second icmp form a subset of values satisfying the first.
/// This handles cases like:
///   (icmp ult i8 %a, 5) && (icmp eq i8 (and %a, -2), 2)
/// Since (and %a, -2) == 2 implies %a is in {2, 3}, which is a subset of {0, 1, 2, 3, 4}.
static Value *trySimplifyAndOfRangeAndMasked(ICmpInst *ICmp1, ICmpInst *ICmp2,
                                              bool IsAnd,
                                              InstCombiner::BuilderTy &Builder) {
  if (!IsAnd)
    return nullptr;

  CmpPredicate Pred1 = ICmp1->getPredicate();
  CmpPredicate Pred2 = ICmp2->getPredicate();
  Value *V1 = ICmp1->getOperand(0);
  Value *V2 = ICmp2->getOperand(0);
  const APInt *C1 = nullptr, *C2 = nullptr;
  if (!match(ICmp1->getOperand(1), m_APInt(C1)) ||
      !match(ICmp2->getOperand(1), m_APInt(C2)))
    return nullptr;

  // Try matching: (icmp ult/ule V1, C1) & (icmp eq (and V2, Mask), C2)
  // where the second is implied by the first.
  if (ICmpInst::isUnsigned(Pred1) && 
      (Pred1 == ICmpInst::ICMP_ULT || Pred1 == ICmpInst::ICMP_ULE) &&
      Pred2 == ICmpInst::ICMP_EQ) {
    Value *X = nullptr;
    const APInt *Mask = nullptr;
    // Check if V2 is (and X, Mask) where X is same as V1
    if (match(V2, m_And(m_Value(X), m_APInt(Mask))) && X == V1) {
      // Calculate the set of values that satisfy (X & Mask) == C2
      // These are values where bits in ~Mask can be anything,
      // bits in Mask must equal C2.
      // Valid if: x >= C2 && x <= (C2 | ~Mask) (all bits in Mask match C2)
      APInt Lo = *C2;
      APInt Hi = *C2 | ~(*Mask);
      // For valid mask, we need C2 & ~Mask == 0 (i.e., C2 only has bits from Mask set)
      if ((*C2 & ~(*Mask)).isZero()) {
        // Check if [Lo, Hi] is within [0, C1] for ult/ule
        APInt UpperBound = (Pred1 == ICmpInst::ICMP_ULT) ? *C1 : (*C1 + 1);
        if (Hi.ult(UpperBound) || (Hi == UpperBound - 1)) {
          // The second comparison implies the first, return just the second.
          return ICmp2;
        }
      }
    }
  }

  // Try the other order: first is masked, second is range check
  if (ICmpInst::isUnsigned(Pred2) &&
      (Pred2 == ICmpInst::ICMP_ULT || Pred2 == ICmpInst::ICMP_ULE) &&
      Pred1 == ICmpInst::ICMP_EQ) {
    Value *X = nullptr;
    const APInt *Mask = nullptr;
    if (match(V1, m_And(m_Value(X), m_APInt(Mask))) && X == V2) {
      APInt Lo = *C1;
      APInt Hi = *C1 | ~(*Mask);
      if ((*C1 & ~(*Mask)).isZero()) {
        APInt UpperBound = (Pred2 == ICmpInst::ICMP_ULT) ? *C2 : (*C2 + 1);
        if (Hi.ult(UpperBound) || (Hi == UpperBound - 1)) {
          return ICmp1;
        }
      }
    }
  }

  return nullptr;
}

